### Swift Methods

Methods are functions that are associated with a particular type. Swift supports instance methods (called on instances) and type methods (called on the type itself).

**Instance Methods:**

```swift
struct Counter {
    var count = 0

    // Instance method
    func description() -> String {
        return "Count: \(count)"
    }

    // Mutating method (can modify properties in struct)
    mutating func increment() {
        count += 1
    }

    mutating func reset() {
        count = 0
    }
}

var counter = Counter()
counter.increment()
counter.increment()
print(counter.description())  // Count: 2
```

**Mutating Methods:**

| Scenario | `mutating` needed? |
|----------|-------------------|
| Struct method modifies property | Yes |
| Class method modifies property | No (classes are reference types) |
| Enum method modifies self | Yes |

```swift
struct Point {
    var x = 0.0, y = 0.0

    mutating func moveBy(x deltaX: Double, y deltaY: Double) {
        x += deltaX
        y += deltaY
    }
}

var point = Point()
point.moveBy(x: 5.0, y: 3.0)
```

**The `self` Property:**

```swift
struct Person {
    var name: String

    func introduce() {
        print("Hi, I'm \(self.name)")
    }

    // Use self to disambiguate parameter names
    mutating func setName(_ name: String) {
        self.name = name
    }
}
```

**Type Methods (Static):**

```swift
struct MathUtils {
    static func factorial(_ n: Int) -> Int {
        guard n > 1 else { return 1 }
        return n * factorial(n - 1)
    }
}

print(MathUtils.factorial(5))  // 120
```

> **Key Point:** Use `mutating` keyword for struct and enum methods that modify properties. Classes do not need `mutating`.

Methods have implicit access to `self`, which refers to the instance itself. Use `self` to disambiguate between parameter names and property names.

codeExample:
import Foundation

struct ToggleSwitch {
    var isOn = false

    // Mutating method
    mutating func toggle() {
        isOn.toggle()
        print("Switch is now \(isOn ? "ON" : "OFF")")
    }

    // Non-mutating method
    func status() -> String {
        return isOn ? "Enabled" : "Disabled"
    }
}

var light = ToggleSwitch()
print(light.status())
light.toggle()
print(light.status())

// Type method
struct Conversion {
    static func celsiusToFahrenheit(_ celsius: Double) -> Double {
        celsius * 9 / 5 + 32
    }

    static func fahrenheitToCelsius(_ fahrenheit: Double) -> Double {
        (fahrenheit - 32) * 5 / 9
    }
}

print("100°C = \(Conversion.celsiusToFahrenheit(100))°F")
print("212°F = \(String(format: "%.1f", Conversion.fahrenheitToCelsius(212)))°C")
